import{_ as t,C as i,o as n,c as A,a2 as E,E as a,j as l,a as B}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Agent Loop 笔记：别让模型循环失控","description":"","frontmatter":{},"headers":[],"relativePath":"agent/agent-loop-notes.md","filePath":"agent/agent-loop-notes.md","lastUpdated":1782239373000}'),r={name:"agent/agent-loop-notes.md"};function p(d,e,s,c,u,g){const o=i("Mermaid");return n(),A("div",null,[e[0]||(e[0]=E('<h1 id="agent-loop-笔记-别让模型循环失控" tabindex="-1">Agent Loop 笔记：别让模型循环失控 <a class="header-anchor" href="#agent-loop-笔记-别让模型循环失控" aria-label="Permalink to &quot;Agent Loop 笔记：别让模型循环失控&quot;">​</a></h1><p>Agent Loop 最容易被写成一个 while 循环：模型输出，检查有没有工具调用，有就执行工具，把结果塞回去，再问模型。这个结构很直观，但真实系统里远远不够。</p><p>我现在对 Agent Loop 的理解是：它不是自动思考的表演，而是一个可恢复的执行系统。模型只是系统里的一个参与方，工具、状态、事件、预算、取消、人工输入都在这个循环里。</p><h2 id="最早的问题" tabindex="-1">最早的问题 <a class="header-anchor" href="#最早的问题" aria-label="Permalink to &quot;最早的问题&quot;">​</a></h2><p>早期 Loop 跑简单任务很顺。用户问问题，模型需要工具就调工具，工具结果回来，模型给最终答案。</p><p>真正的问题出现在异常路径：</p><ul><li>工具失败后，模型可能反复尝试。</li><li>同一个工具可能被重复调用，甚至产生重复副作用。</li><li>上下文越来越长，工具调用和工具结果可能被压缩切断。</li><li>用户点取消，但模型流或工具任务还在后台运行。</li><li>模型已经流式输出一半，再失败时不好重试。</li><li>工具需要用户确认时，系统不知道该如何暂停和恢复。</li></ul><p>这些问题说明 Loop 不能只靠模型自觉停下来。</p><h2 id="当前更稳的-loop-结构" tabindex="-1">当前更稳的 Loop 结构 <a class="header-anchor" href="#当前更稳的-loop-结构" aria-label="Permalink to &quot;当前更稳的 Loop 结构&quot;">​</a></h2>',9)),a(o,{code:"flowchart%20TD%0A%20%20%20%20Start%5B%22%E6%8E%A5%E6%94%B6%E4%BB%BB%E5%8A%A1%22%5D%20--%3E%20Context%5B%22%E6%9E%84%E5%BB%BA%E4%B8%8A%E4%B8%8B%E6%96%87%22%5D%0A%20%20%20%20Context%20--%3E%20Model%5B%22%E6%A8%A1%E5%9E%8B%E8%B0%83%E7%94%A8%20%2F%20%E6%B5%81%E5%BC%8F%E8%BE%93%E5%87%BA%22%5D%0A%20%20%20%20Model%20--%3E%20Decision%7B%22%E6%98%AF%E5%90%A6%E8%AF%B7%E6%B1%82%E5%B7%A5%E5%85%B7%22%7D%0A%20%20%20%20Decision%20--%20%22%E5%90%A6%22%20--%3E%20Complete%5B%22%E5%AE%8C%E6%88%90%E5%B9%B6%E5%86%99%E7%BB%88%E6%80%81%22%5D%0A%20%20%20%20Decision%20--%20%22%E6%98%AF%22%20--%3E%20Policy%5B%22%E5%B7%A5%E5%85%B7%E7%AD%96%E7%95%A5%E6%A3%80%E6%9F%A5%22%5D%0A%20%20%20%20Policy%20--%3E%20NeedHuman%7B%22%E9%9C%80%E8%A6%81%E5%AE%A1%E6%89%B9%E6%88%96%E8%BE%93%E5%85%A5%3F%22%7D%0A%20%20%20%20NeedHuman%20--%20%22%E6%98%AF%22%20--%3E%20Wait%5B%22%E8%BF%9B%E5%85%A5%E7%AD%89%E5%BE%85%E7%8A%B6%E6%80%81%22%5D%0A%20%20%20%20Wait%20--%3E%20Resume%5B%22%E7%94%A8%E6%88%B7%E5%93%8D%E5%BA%94%E5%90%8E%E6%81%A2%E5%A4%8D%22%5D%0A%20%20%20%20Resume%20--%3E%20Context%0A%20%20%20%20NeedHuman%20--%20%22%E5%90%A6%22%20--%3E%20Execute%5B%22%E6%89%A7%E8%A1%8C%E5%B7%A5%E5%85%B7%22%5D%0A%20%20%20%20Execute%20--%3E%20Observe%5B%22%E5%8C%85%E8%A3%85%E8%A7%82%E5%AF%9F%E7%BB%93%E6%9E%9C%22%5D%0A%20%20%20%20Observe%20--%3E%20Budget%7B%22%E9%A2%84%E7%AE%97%E6%98%AF%E5%90%A6%E8%80%97%E5%B0%BD%22%7D%0A%20%20%20%20Budget%20--%20%22%E5%90%A6%22%20--%3E%20Model%0A%20%20%20%20Budget%20--%20%22%E6%98%AF%22%20--%3E%20Fallback%5B%22%E9%99%8D%E7%BA%A7%E6%94%B6%E5%B0%BE%22%5D%0A%0A%20%20%20%20Model%20--%3E%20Cancel%7B%22%E5%8F%96%E6%B6%88%20%2F%20%E8%B6%85%E6%97%B6%20%2F%20%E5%BC%82%E5%B8%B8%22%7D%0A%20%20%20%20Execute%20--%3E%20Cancel%0A%20%20%20%20Cancel%20--%20%22%E8%A7%A6%E5%8F%91%22%20--%3E%20Terminal%5B%22%E5%86%99%E5%85%A5%E5%A4%B1%E8%B4%A5%E3%80%81%E5%8F%96%E6%B6%88%E6%88%96%E8%B6%85%E6%97%B6%E7%BB%88%E6%80%81%22%5D%0A"}),e[1]||(e[1]=l("p",null,"这个循环里，关键不是“模型还能不能继续想”，而是每一步都要能被系统接住。",-1)),e[2]||(e[2]=l("p",null,"工具执行前，要检查 allowlist、风险、审批、调用次数。工具执行后，要把输出包装成不可信观察结果。模型继续之前，要检查预算。用户中断时，要进入明确状态，而不是停在某个内存栈里。",-1)),e[3]||(e[3]=l("h2",{id:"状态机比-while-循环重要",tabindex:"-1"},[B("状态机比 while 循环重要 "),l("a",{class:"header-anchor",href:"#状态机比-while-循环重要","aria-label":'Permalink to "状态机比 while 循环重要"'},"​")],-1)),a(o,{code:"stateDiagram-v2%0A%20%20%20%20%5B*%5D%20--%3E%20Pending%0A%20%20%20%20Pending%20--%3E%20BuildingContext%0A%20%20%20%20BuildingContext%20--%3E%20ModelCalling%0A%20%20%20%20ModelCalling%20--%3E%20Streaming%0A%20%20%20%20Streaming%20--%3E%20ToolExecuting%0A%20%20%20%20ToolExecuting%20--%3E%20ModelCalling%0A%20%20%20%20Streaming%20--%3E%20WaitingInput%0A%20%20%20%20WaitingInput%20--%3E%20BuildingContext%0A%20%20%20%20Streaming%20--%3E%20Completed%0A%20%20%20%20ModelCalling%20--%3E%20Failed%0A%20%20%20%20ToolExecuting%20--%3E%20Failed%0A%20%20%20%20BuildingContext%20--%3E%20Cancelled%0A%20%20%20%20Streaming%20--%3E%20Cancelled%0A%20%20%20%20ToolExecuting%20--%3E%20Timeout%0A%20%20%20%20Completed%20--%3E%20%5B*%5D%0A%20%20%20%20Failed%20--%3E%20%5B*%5D%0A%20%20%20%20Cancelled%20--%3E%20%5B*%5D%0A%20%20%20%20Timeout%20--%3E%20%5B*%5D%0A"}),e[4]||(e[4]=E('<p>状态机的价值是让系统知道自己在哪里。没有状态机时，取消、恢复、超时都会变成一堆 if。</p><p>等待用户输入尤其要进入状态机。它不是 UI 弹窗，而是执行过程的一部分。系统要知道：为什么停，等谁回答，回答后怎么恢复。</p><h2 id="reflection-不一定要做成角色" tabindex="-1">Reflection 不一定要做成角色 <a class="header-anchor" href="#reflection-不一定要做成角色" aria-label="Permalink to &quot;Reflection 不一定要做成角色&quot;">​</a></h2><p>我以前也想做一个单独的 Reflection Agent。后来发现，很多反思可以先工程化：</p><ul><li>工具失败多次后停止重试。</li><li>重复工具调用被预算拦住。</li><li>产物生成后做校验。</li><li>循环达到上限后让模型做最终合成。</li><li>完成后提取候选记忆。</li></ul><p>这些机制比让模型写一句“我反思了”更有用。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>工具副作用重复执行是大坑。只读工具问题不大，但写文件、写记忆、调用外部系统时，重试和恢复都可能造成重复副作用。Loop 要有幂等意识。</p><p>取消也容易做假。只把任务状态改成 cancelled，并不代表模型流和工具任务真的停了。取消必须尽量传到执行端。</p><p>上下文压缩也要小心。不能把 tool call 和 tool result 切开，否则下一轮模型会看到不完整历史。</p><p>流式失败要分阶段处理。模型还没输出时，可以考虑切换候选模型；已经输出后，就不能简单重放。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果重新做 Loop，我会先定义状态和事件，再写模型调用。模型调用只是一个节点，不是整个 Loop。</p><p>我也会从第一版就加预算、取消、工具幂等和等待恢复。越晚补，返工越大。</p><p>一句话总结：Agent Loop 的重点不是让模型一直想，而是让模型、工具、用户输入和失败都能被可恢复的执行系统接住。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>Agent Loop 为什么不是普通 while 循环。</li><li>工具失败和重复调用如何让 Loop 失控。</li><li>状态机在取消、恢复、等待输入里的作用。</li><li>工具观察结果为什么要包装成不可信输入。</li><li>Reflection 为什么可以先工程化。</li><li>流式失败和普通失败有什么区别。</li><li>如果重做，为什么先写状态和事件。</li></ol>',17))])}const D=t(r,[["render",p]]);export{m as __pageData,D as default};
